import { PATH_ELEMENT } from '../../../core/element-constants';
import { TRACK_FLASH_CLASSNAME, TRACK_LEGEND_CLASSNAME } from '../../../legend/legend-constants';
import { CHART_BRUSH_HELPERS } from '../../../brush/chart-helpers/brush-helpers';

export function BrushClip(behaviour, chart) {
    let brushInstance = behaviour.instance,
        element = brushInstance.options.component.element,
        flashElement = element.selectAll(`g.${TRACK_LEGEND_CLASSNAME}`).selectAll(`${PATH_ELEMENT}.${TRACK_FLASH_CLASSNAME}`),
        desc = flashElement.attr('d') || '';

    let clipPath = CHART_BRUSH_HELPERS.CLIP_TRACK(brushInstance, [0, 0], chart, 'size_slider_brush', { desc });
    brushInstance._selection.attr('clip-path', clipPath);
}
